#include<bits/stdc++.h>
using namespace std;
struct node
{
    int val,lson,rson;
}a[100010];
int dis[100010],fa[100010],root[100010];
bool del[100010];
int find(int x)
{
    return(x==fa[x]?x:fa[x]=find(fa[x]));
}
int merge(int x,int y)
{
    if(x==0||y==0)
    {
        return x+y;
    }
    if(a[x].val<a[y].val)
    {
        swap(x,y);
    }
    a[x].rson=merge(a[x].rson,y);
    if(dis[a[x].lson]<dis[a[x].rson])
    {
        swap(a[x].lson,a[x].rson);
    }
    dis[x]=dis[a[x].rson]+1;
    return x;
}
int main()
{
    int n,m;
    while(scanf("%d",&n)!=EOF)
    {
        for(int i=1;i<=n;i++)
        {
            scanf("%d",&a[i].val);
            fa[i]=root[i]=i;
            a[i].lson=a[i].rson=0;
        }
        scanf("%d",&m);
        while(m--)
        {
            int x,y;
            scanf("%d%d",&x,&y);
            if(find(x)==find(y))
            {
                printf("-1\n");
                continue;
            }
            int u=root[find(x)],v=root[find(y)];
            root[find(x)]=merge(a[u].lson,a[u].rson);
            a[u].val/=2;
            a[u].lson=a[u].rson=0;
            root[find(x)]=merge(root[find(x)],u);
            root[find(y)]=merge(a[v].lson,a[v].rson);
            a[v].val/=2;
            a[v].lson=a[v].rson=0;
            root[find(y)]=merge(root[find(y)],v);
            u=root[find(x)],v=root[find(y)];
            fa[find(x)]=find(y);
            root[find(x)]=merge(u,v);
            printf("%d\n",a[root[find(x)]].val);
        }
    }
    return 0;
}
